import React, { useEffect, useState } from 'react';
import { Row, Col, Card, Image, Descriptions, Typography, List } from 'antd';
import { useParams, useLocation, Link } from 'react-router-dom';
import Loading from 'components/Loading';
import { getProduct } from 'requests/product';
import PageTitle from 'components/PageTitle';
import Parse from 'html-react-parser';

const { Title } = Typography;

function ProductDetail(props) {
	const [titles, setTitles] = useState([{ path: '/products', title: 'Products' }]);
	const [product, setProduct] = useState({});
	const [loading, setLoading] = useState(true);

	const params = useParams();
	const location = useLocation();

	useEffect(() => {
		const getData = async () => {
			const productDetail = await getProduct(params.id);

			setTitles([
				{ path: '/products', title: 'Products' },
				{ path: location.pathname, title: productDetail.name },
			]);
			setProduct(productDetail);
			setLoading(false);
		};

		getData();
	}, []);
	return (
		<div>
			<PageTitle titles={titles} />
			{loading ? (
				<Loading />
			) : (
				<Row gutter={[16, 16]} className="mb-36 mt-36">
					<Col xs={24} sm={24} md={14} lg={14}>
						<Card>
							<Row gutter={[16, 16]}>
								<Col xs={24} sm={24} md={10}>
									<Image
										src={product.image || 'error'}
										width="100%"
										height="100%"
										fallback="data:image/png;base64,"
									/>
								</Col>
								<Col xs={24} sm={24} md={14}>
									<Descriptions column={1} size="small" layout="horizontal">
										<Descriptions.Item label="ID">{product.id}</Descriptions.Item>
										<Descriptions.Item label="Platform Product ID">
											{product.platform_product_id}
										</Descriptions.Item>
										<Descriptions.Item label="SKU">{product.sku}</Descriptions.Item>
										<Descriptions.Item label="Weight">{product.weight}kg</Descriptions.Item>
										<Descriptions.Item label="Height">{product.height}cm</Descriptions.Item>
										<Descriptions.Item label="Width">{product.width}cm</Descriptions.Item>
										<Descriptions.Item label="Length">{product.length}cm</Descriptions.Item>
										<Descriptions.Item label="HNS">{product.hns}</Descriptions.Item>
										<Descriptions.Item label="Price">{product.store?.currency} {product.price}</Descriptions.Item>
									</Descriptions>
								</Col>
							</Row>
						</Card>
						{product.description ? (
							<Card className="mt-24">
								<Title level={5} className="text-gray">
									Descriptions
								</Title>
								<div>{Parse(product.description)}</div>
							</Card>
						) : null}
					</Col>

					<Col xs={24} sm={24} md={8} lg={8}>
						<Card>
							<Title level={5} className="text-gray">Store</Title>
							<div>
								<Link to={`/stores/${product.user_store_id}`}>{product.store?.store_name}</Link>
							</div>
						</Card>
						{product.variations.length > 0 && (
							<Card className="mt-24">
								<Title level={5} className="text-gray">
									Variations
								</Title>
								<List
									size="small"
									dataSource={product.variations}
									renderItem={(item, index) => {
										const options = item.options.map(option => `${option.name}: ${option.value}`);

										return (
											<List.Item>
												<div>
													<strong>{`Variation ${index + 1} `}</strong>
													<div>
														<small>{options.join(' - ')}</small>
													</div>
													<div>
														<small>{item.defaultDisplayedPriceFormatted}</small>
													</div>
												</div>
											</List.Item>
										)
									}}
								/>
							</Card>
						)}
					</Col>
				</Row>
			)}
		</div>
	);
}

export default ProductDetail;
